[System.Reflection.Assembly]::LoadWithPartialName("System.windows.forms")|Out-Null;[System.Reflection.Assembly]::LoadWithPartialName("System.drawing")|Out-Null;if(-not([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]"Administrator")){[System.Windows.Forms.MessageBox]::Show("Please run PowerShell as Administrator!","Error",[System.Windows.Forms.MessageBoxButtons]::OK,[System.Windows.Forms.MessageBoxIcon]::Error);exit 1};$form=New-Object System.Windows.Forms.Form;$form.Text="Driver Installer - Hardware Detection";$form.Size=New-Object System.Drawing.Size(900,700);$form.StartPosition="CenterScreen";$form.Font=New-Object System.Drawing.Font("Segoe UI",10);$titleLabel=New-Object System.Windows.Forms.Label;$titleLabel.Text="Detected Hardware & Drivers";$titleLabel.Location=New-Object System.Drawing.Point(10,10);$titleLabel.Size=New-Object System.Drawing.Size(400,30);$titleLabel.Font=New-Object System.Drawing.Font("Segoe UI",14,[System.Drawing.FontStyle]::Bold);$form.Controls.Add($titleLabel);$statusLabel=New-Object System.Windows.Forms.Label;$statusLabel.Text="Detecting hardware...";$statusLabel.Location=New-Object System.Drawing.Point(10,45);$statusLabel.Size=New-Object System.Drawing.Size(300,20);$statusLabel.ForeColor=[System.Drawing.Color]::Blue;$form.Controls.Add($statusLabel);$listBox=New-Object System.Windows.Forms.ListBox;$listBox.Location=New-Object System.Drawing.Point(10,70);$listBox.Size=New-Object System.Drawing.Size(400,300);$listBox.Font=New-Object System.Drawing.Font("Courier New",9);$form.Controls.Add($listBox);$driverListBox=New-Object System.Windows.Forms.ListBox;$driverListBox.Location=New-Object System.Drawing.Point(420,70);$driverListBox.Size=New-Object System.Drawing.Size(460,300);$driverListBox.Font=New-Object System.Drawing.Font("Courier New",9);$form.Controls.Add($driverListBox);$downloadBtn=New-Object System.Windows.Forms.Button;$downloadBtn.Text="Download Selected";$downloadBtn.Location=New-Object System.Drawing.Point(420,380);$downloadBtn.Size=New-Object System.Drawing.Size(220,40);$downloadBtn.Font=New-Object System.Drawing.Font("Segoe UI",10,[System.Drawing.FontStyle]::Bold);$downloadBtn.BackColor=[System.Drawing.Color]::LimeGreen;$downloadBtn.ForeColor=[System.Drawing.Color]::White;$form.Controls.Add($downloadBtn);$copyBtn=New-Object System.Windows.Forms.Button;$copyBtn.Text="Copy URL";$copyBtn.Location=New-Object System.Drawing.Point(650,380);$copyBtn.Size=New-Object System.Drawing.Size(220,40);$copyBtn.Font=New-Object System.Drawing.Font("Segoe UI",10);$form.Controls.Add($copyBtn);$infoBox=New-Object System.Windows.Forms.TextBox;$infoBox.Location=New-Object System.Drawing.Point(10,430);$infoBox.Size=New-Object System.Drawing.Size(870,230);$infoBox.Multiline=$true;$infoBox.ReadOnly=$true;$infoBox.Font=New-Object System.Drawing.Font("Courier New",9);$infoBox.ScrollBars="Vertical";$form.Controls.Add($infoBox);$driverData=@();function DetectHardware{$statusLabel.Text="Detecting hardware...";$form.Refresh();$info="=== HARDWARE DETECTION STARTED ===`n`n";$gpus=@();Get-WmiObject Win32_VideoController -EA 0|Where-Object{$_.Name}|ForEach-Object{if($_.Name -like "*NVIDIA*"){$gpus+=@{Type="GPU";Name=$_.Name;Manufacturer="NVIDIA"};$info+="[GPU] NVIDIA: $($_.Name)`n"}if($_.Name -like "*AMD*" -or $_.Name -like "*Radeon*"){$gpus+=@{Type="GPU";Name=$_.Name;Manufacturer="AMD"};$info+="[GPU] AMD: $($_.Name)`n"}if($_.Name -like "*Intel*"){$gpus+=@{Type="GPU";Name=$_.Name;Manufacturer="Intel"};$info+="[GPU] Intel: $($_.Name)`n"}};$devices=@();Get-WmiObject Win32_NetworkAdapterConfiguration -EA 0|Where-Object{$_.Description}|ForEach-Object{$devices+=@{Type="Network";Name=$_.Description};$info+="[Network] $($_.Description)`n"};Get-WmiObject Win32_SoundDevice -EA 0|Where-Object{$_.Name}|ForEach-Object{$devices+=@{Type="Audio";Name=$_.Name};$info+="[Audio] $($_.Name)`n"};Get-WmiObject Win32_IDEController -EA 0|Where-Object{$_.Name}|ForEach-Object{$devices+=@{Type="Storage";Name=$_.Name};$info+="[Storage] $($_.Name)`n"};Get-WmiObject Win32_BaseBoard -EA 0|ForEach-Object{$devices+=@{Type="Motherboard";Name="$($_.Manufacturer) $($_.Product)"};$info+="[Motherboard] $($_.Manufacturer) $($_.Product)`n"};$info+="`n=== ADDING TO UI ===`n";$listBox.Items.Clear();foreach($gpu in $gpus){$listBox.Items.Add("[GPU] $($gpu.Manufacturer): $($gpu.Name)")};foreach($dev in $devices){$listBox.Items.Add("[$($dev.Type)] $($dev.Name)")};$driverListBox.Items.Clear();$script:driverData=@();if($gpus|Where-Object{$_.Manufacturer -eq "NVIDIA"}){$driverListBox.Items.Add("NVIDIA Drivers");$script:driverData+=@{Name="NVIDIA Drivers";URL="https://www.nvidia.com/Download/index.aspx"};$info+="Added: NVIDIA driver link`n"};if($gpus|Where-Object{$_.Manufacturer -eq "AMD"}){$driverListBox.Items.Add("AMD Radeon Drivers");$script:driverData+=@{Name="AMD Radeon Drivers";URL="https://www.amd.com/en/technologies/radeon-software"};$info+="Added: AMD driver link`n"};if($gpus|Where-Object{$_.Manufacturer -eq "Intel"}){$driverListBox.Items.Add("Intel Arc Drivers");$script:driverData+=@{Name="Intel Arc Drivers";URL="https://www.intel.com/content/www/us/en/download/785597/intel-arc-graphics-driver.html"};$info+="Added: Intel driver link`n"};$mb=Get-WmiObject Win32_BaseBoard -EA 0;if($mb){if($mb.Manufacturer.ToLower()-like "*intel*"){$driverListBox.Items.Add("Intel Chipset Drivers");$script:driverData+=@{Name="Intel Chipset Drivers";URL="https://www.intel.com/content/www/us/en/download/17596/intel-chipset-device-software.html"};$info+="Added: Intel Chipset link`n"};if($mb.Manufacturer.ToLower()-like "*amd*"){$driverListBox.Items.Add("AMD Chipset Drivers");$script:driverData+=@{Name="AMD Chipset Drivers";URL="https://www.amd.com/en/support"};$info+="Added: AMD Chipset link`n"}};$infoBox.Text=$info;$statusLabel.Text="Detection complete! Detected $($listBox.Items.Count) devices and $($driverListBox.Items.Count) driver links";$statusLabel.ForeColor=[System.Drawing.Color]::Green};$downloadBtn.Add_Click({if($driverListBox.SelectedIndex-ge 0){$selected=$driverListBox.SelectedIndex;if($selected-lt $script:driverData.Count){$url=$script:driverData[$selected].URL;Start-Process $url;$infoBox.AppendText("`n[$(Get-Date -Format 'HH:mm:ss')] Opened: $url`n")}}});$copyBtn.Add_Click({if($driverListBox.SelectedIndex-ge 0){$selected=$driverListBox.SelectedIndex;if($selected-lt $script:driverData.Count){$url=$script:driverData[$selected].URL;[System.Windows.Forms.Clipboard]::SetText($url);[System.Windows.Forms.MessageBox]::Show("Copied: $url","Copied to Clipboard");$infoBox.AppendText("`n[$(Get-Date -Format 'HH:mm:ss')] Copied: $url`n")}}});DetectHardware;$form.ShowDialog()|Out-Null
